const sheets = {};

for (const item of $input.all()) {
  const name = item.json.sheetName ?? 'Sheet1';
  if (!sheets[name]) sheets[name] = [];
  sheets[name].push(item.json);
}

return Object.entries(sheets).map(([name, rows]) => ({
  json: {
    sheetName: name,
    rows: rows
  }
}));
